const fs = require("fs");
const path = require("path");

// Data layer for /geneva-reflections/story/ — the story-first companion to
// the original data report. Reads site-data/computed.json, generated by
// scripts/story_compute.py from the 15:05 Pol.is export. Every number on the
// story page comes from here; nothing is hand-typed into markup.
// The original report keeps its own pipeline (analyze.py -> results.json,
// 09:00 export) — the two are intentionally separate snapshots.
const COMPUTED = path.join(__dirname, "../../../site-data/computed.json");

module.exports = () => {
  const c = JSON.parse(fs.readFileSync(COMPUTED, "utf-8"));

  c.stats.total_votes_display = c.stats.total_votes.toLocaleString("en-US");
  c.maxVotes = Math.max(...c.participants.map((p) => p.n_votes));
  c.top10_live = c.top10_consensus.filter((t) => t.source === "live").length;

  return c;
};
